extern "C" const char *m14_lane_token(const forge::UnitSpec *units, size_t count) {
    static thread_local std::string cached;
    std::vector<forge::UnitSpec> sorted;
    sorted.reserve(count);
    for (size_t i = 0; i < count; ++i) {
        sorted.push_back(units[i]);
    }
    std::sort(sorted.begin(), sorted.end(), [](const forge::UnitSpec &a, const forge::UnitSpec &b) {
        return a.name < b.name;
    });

    std::ostringstream joined;
    for (size_t i = 0; i < sorted.size(); ++i) {
        if (i) {
            joined << '\n';
        }
        joined << sorted[i].name << '|' << sorted[i].mode << '|' << sorted[i].record_path << '|'
               << sorted[i].manifest_bytes << '|' << sorted[i].start_pass;
    }

    cached = forge::digest_hex(joined.str());
    return cached.c_str();
}

