    if (doc.find("\"schema_version\"") == std::string::npos) {
        return state;
    }
    state.lane_token = forge::pick_string(doc, "lane_token");
    if (!m14_checkpoint_valid(state.lane_token.c_str(), expected_token.c_str())) {
        return state;
    }
    state.pass_epoch = forge::pick_int(doc, "pass_epoch");

    size_t units_pos = doc.find("\"units\"");
    if (units_pos == std::string::npos) {
        state.valid = true;
        return state;
    }
    size_t arr_start = doc.find('[', units_pos);
    size_t arr_end = doc.find(']', arr_start);
    if (arr_start == std::string::npos || arr_end == std::string::npos) {
        return state;
    }
    const std::string arr = doc.substr(arr_start, arr_end - arr_start + 1);
    for (const auto &block : forge::split_object_blocks(arr)) {
        forge::UnitCheckpoint entry;
        entry.name = forge::pick_string(block, "name");
        entry.next_pass = forge::pick_int(block, "next_pass");
        entry.carry_weight = forge::pick_int64(block, "carry_weight");
        entry.carry_drift = forge::pick_int64(block, "carry_drift");
        if (!entry.name.empty()) {
            state.units[entry.name] = entry;
        }
    }
    state.valid = true;
    return state;
}

